    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, MinimumLength = 1, ErrorMessage = "Name must be between 1 and 100 characters.")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Quantity is required.")]
    [Range(0, int.MaxValue, ErrorMessage = "Quantity must be 0 or greater.")]
    public int Quantity { get; set; }

    [Required(ErrorMessage = "Unit Price is required.")]
    [Range(0.01, double.MaxValue, ErrorMessage = "Unit Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public ProductCategory Category { get; set; }
}

public enum ProductCategory
{
    Electronics,
    Clothing,
    Food,
    Other
}

using sv_f86083346e824dc891d6fa69b34383a0.Models;

namespace sv_f86083346e824dc891d6fa69b34383a0.Services;

public class InventoryService
{
    private readonly Lock _lock = new();
    private readonly List<Product> _products;
    private int _nextId;

    public InventoryService()
    {
        _products = new List<Product>
        {
            new() { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = ProductCategory.Electronics },
            new() { Id = 2, Name = "USB-C Cable", Quantity = 300, UnitPrice = 12.49m, Category = ProductCategory.Electronics },
            new() { Id = 3, Name = "Cotton T-Shirt", Quantity = 200, UnitPrice = 19.95m, Category = ProductCategory.Clothing },
            new() { Id = 4, Name = "Winter Jacket", Quantity = 50, UnitPrice = 89.99m, Category = ProductCategory.Clothing },
            new() { Id = 5, Name = "Organic Coffee Beans", Quantity = 120, UnitPrice = 14.75m, Category = ProductCategory.Food },
            new() { Id = 6, Name = "Granola Bars (12pk)", Quantity = 80, UnitPrice = 6.99m, Category = ProductCategory.Food },
        };
        _nextId = 7;
    }

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList());
        }
    }

    public Task AddAsync(Product product)
    {
        lock (_lock)
        {
            product.Id = _nextId++;
            _products.Add(new Product
            {
                Id = product.Id,
                Name = product.Name,
                Quantity = product.Quantity,
                UnitPrice = product.UnitPrice,
                Category = product.Category
            });
        }
        return Task.CompletedTask;
    }

    public Task<bool> UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is null) return Task.FromResult(false);

            existing.Name = product.Name;
            existing.Quantity = product.Quantity;
            existing.UnitPrice = product.UnitPrice;
            existing.Category = product.Category;
            return Task.FromResult(true);
        }
    }
}

